function isSelfDividing(num) {
    let n = num;
    while (n) {
        const digit = n % 10;
        if (digit === 0 || num % digit !== 0)
            return false;
        n = Math.floor(n / 10);
    }
    return true;
}

function selfDividingNumbers(left, right) {
    const result = [];
    for (let i = left; i <= right; ++i) {
        if (isSelfDividing(i))
            result.push(i);
    }
    return result;
}
